function stripAndRedact(lines: string[], options: NormalizedErrorStackOptions): string[] {
  const [header, ...frames] = lines;
  const kept = frames.filter(frame => {
    const node = frame.includes('node:internal');
    const superjson = /src\/(?:transformer|plainer|index)\.ts/.test(frame);
    return !(
