      (options.stripInternalFrames === 'superjson' && superjson) ||
      (options.stripInternalFrames === 'node_and_superjson' && (node || superjson))
    );
  });
  return [header, ...kept].map((line, index) =>
    index === 0 ? line : redactPath(line, options.redactPaths)
  );
}

function redactPath(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
  if (mode === 'none') return line;
  if (mode === 'strip_cwd') {
    const cwd = process.cwd().replace(/\\/g, '/').replace(/\/$/, '');
    return line.replace(new RegExp(escapeRegExp(cwd.replace(/\\/g, '/')), 'g'), '');
  }
  return line.replace(/(?:file:\/\/)?(?:[A-Za-z]:)?(?:\/|\\)[^\s()]+/g, match => {
    const normalized = match.replace(/\\/g, '/');
    return normalized.slice(normalized.lastIndexOf('/') + 1);
  });
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function prepareLines(stack: string, options: NormalizedErrorStackOptions): string[] {
  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  const lines = normalized.split('\n');
  if (options.trimLeadingWhitespace) {
    for (let index = 1; index < lines.length; index++) lines[index] = lines[index].replace(/^\s+/, '');
  }
  return lines;
}

export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
  let lines = prepareLines(stack, options);
